// Extraire les URLs individuelles depuis la liste
const results = $input.first().json.results;
const items = results.map(p => ({ json: { url: p.url, name: p.name } }));
return items;

// Transformation des données brutes en format structuré
const items = $input.all();
const now = new Date().toISOString();

// Récupérer le run_id depuis le premier noeud
// (à adapter selon votre configuration)
const run_id = 1;

const transformed = items.map(item => {
  const data = item.json;

  // Extraction du type principal (premier type)
  const mainType = (data.types && data.types.length > 0)
    ? data.types[0].type.name
    : 'unknown';

  // Vérification artwork officiel
  const hasOfficialArtwork = !!(data.sprites
    && data.sprites.other
    && data.sprites.other['official-artwork']
    && data.sprites.other['official-artwork'].front_default);

  // Vérification sprite frontal
  const hasFrontSprite = !!(data.sprites && data.sprites.front_default);

  return {
    json: {
      pokemon_id: data.id || 0,
      pokemon_name: (data.name || '').toLowerCase().trim(),
      base_experience: data.base_experience || null,
      height: data.height || null,
      weight: data.weight || null,
      main_type: mainType,
      has_official_artwork: hasOfficialArtwork,
      has_front_sprite: hasFrontSprite,
      source_last_updated_at: now,
      ingested_at: now,
      run_id: run_id
    }
  };
});

return transformed;
